166	// shaReachable returns true when sha is reachable from ref via any commit
167	// path (including through merge commit parents).
168	func (r *landTestRepo) shaReachable(ref, sha string) bool {
169		r.t.Helper()
170		cmd := exec.Command("git", "-C", r.dir, "merge-base", "--is-ancestor", sha, ref)
171		return cmd.Run() == nil
172	}
