359	// TestLand_ConcurrentSubmissions_Serialized spawns N concurrent Land() calls
360	// through a single coordinator-like serialization (sync.Mutex) and asserts
361	// that (a) all N worker commits are reachable from main, (b) each non-first
362	// submission took the merge path and produced a merge commit, and (c) every
363	// worker commit's original parent is preserved (replay fidelity).
364	//
365	// This is a direct test of the "single-writer" contract the server
366	// coordinator enforces, plus the replay-fidelity invariant of the
367	// merge-over-rebase design.
368	func TestLand_ConcurrentSubmissions_Serialized(t *testing.T) {
369		r := newLandTestRepo(t)
370		ops := RealLandingGitOps{}
371	
372		const N = 5
373		// Prepare N worker commits, each branching off the original baseSHA.
374		// Each touches a distinct file so merges always complete cleanly.
375		workerSHAs := make([]string, N)
376		for i := 0; i < N; i++ {
377			workerSHAs[i] = r.commitOn(r.baseSHA, fmt.Sprintf("worker-%d.txt", i), fmt.Sprintf("content-%d\n", i), fmt.Sprintf("feat: worker %d", i))
378		}
379	
380		// Serialize submissions through a mutex — this simulates the coordinator
381		// goroutine. Spawn concurrently so we exercise the lock ordering too.
382		var mu sync.Mutex
383		var wg sync.WaitGroup
384		results := make([]*LandResult, N)
385		errs := make([]error, N)
386		for i := 0; i < N; i++ {
387			i := i
388			wg.Add(1)
389			go func() {
390				defer wg.Done()
391				mu.Lock()
392				defer mu.Unlock()
393				req := LandRequest{
394					WorktreeDir:  r.dir,
395					BaseRev:      r.baseSHA, // all submissions think they branched off the original base
396					ResultRev:    workerSHAs[i],
397					BeadID:       fmt.Sprintf("ddx-concurrent-%02d", i),
398					AttemptID:    fmt.Sprintf("20260414T00%04d-%02d", i, i),
399					TargetBranch: "main",
400				}
401				results[i], errs[i] = Land(r.dir, req, ops)
402			}()
403		}
404		wg.Wait()
405	
406		for i, err := range errs {
407			if err != nil {
408				t.Errorf("submission %d: Land returned error: %v", i, err)
409			}
410			if results[i] == nil || results[i].Status != "landed" {
411				t.Errorf("submission %d: expected landed, got %+v", i, results[i])
412			}
413		}
414	
415		// Exactly one submission took the ff path (the first one under lock);
416		// every subsequent one saw an advanced tip and took the merge path.
417		merged := 0
418		ff := 0
419		for _, res := range results {
420			if res == nil {
421				continue
422			}
423			if res.Merged {
424				merged++
425			} else {
426				ff++
427			}
428		}
429		if ff != 1 {
430			t.Errorf("expected exactly 1 fast-forward submission, got %d", ff)
431		}
432		if merged != N-1 {
433			t.Errorf("expected %d merged submissions, got %d", N-1, merged)
434		}
435	
436		// All N worker commits must be reachable from main.
437		for i, sha := range workerSHAs {
438			if !r.shaReachable("refs/heads/main", sha) {
439				t.Errorf("worker %d commit %s not reachable from main", i, sha)
440			}
441		}
442	
443		// Replay fidelity: every worker commit must still have parent == baseSHA.
444		for i, sha := range workerSHAs {
445			parents := r.commitParents(sha)
446			if len(parents) != 1 || parents[0] != r.baseSHA {
447				t.Errorf("worker %d commit parent = %v, want [%s]", i, parents, r.baseSHA)
448			}
449		}
450	
451		// Each non-ff submission produced exactly one merge commit on main.
452		if n := r.mergeCommitCount("refs/heads/main"); n != N-1 {
453			t.Errorf("expected %d merge commits on main, got %d", N-1, n)
454		}
455	}
